import { MPFacil } from './src/index.js';

if (!process.env.MP_ACCESS_TOKEN) {
  console.log('Defina MP_ACCESS_TOKEN antes de rodar este teste.');
  process.exit(1);
}

const mp = new MPFacil({
  apiKey: process.env.MP_ACCESS_TOKEN,
  sandbox: true,
  autoResumeLoops: false
});

mp.on('pago', (pagamento) => {
  console.log('Pix pago!');
  console.log('Pedido:', pagamento.referencia);
  console.log('Usuario:', pagamento.metadados.idUser);
});

mp.on('recusado', (pagamento) => {
  console.log('Pix recusado:', pagamento.statusDetalhado);
});

mp.on('pendente', (pagamento) => {
  console.log('Pix ainda pendente:', pagamento.id);
});

mp.on('erro', (erro) => {
  console.log('Erro no Pix:', erro);
});

const pix = await mp.criarPix({
  produto: 'clube do cafe - plano mensal',
  id: 'pedido-pix-cafe',
  preco: 0.2,
  emailPagador: 'cliente@example.com',
  metadados: {
    idUser: 'jxd12dd3'
  },
  chaveIdempotencia: `pix-pedido-cafe-${Date.now()}`
});

if (!pix.ok) {
  console.log('Erro ao criar Pix:', pix);
  process.exitCode = 1;
} else {
  console.log('Pix criado com sucesso!');
  console.log('ID do pagamento:', pix.dados.id);
  console.log('Status:', pix.dados.situacao);
  console.log('Pix copia e cola:', pix.dados.copiaECola);
  console.log('QR Code base64:', pix.dados.qrCodeBase64);
  console.log('Link Pix:', pix.dados.ticketUrl);

  const loop = await mp.acompanharCobranca(pix.dados.id, {
    intervaloMs: 5000,
    duracaoMs: 30 * 60 * 1000
  });

  if (!loop.ok) {
    console.log('Erro ao iniciar loop:', loop);
    process.exitCode = 1;
  } else {
    console.log('Loop iniciado para o Pix:', pix.dados.id);
    console.log('Memoria do loop:', loop.dados.arquivo);
  }
}
